example.code:
{
  "provider": "anthropic",
  "budget": {"max_calls_per_turn": 3, "max_content_tokens": 2000},
  "tools": [
    {"name": "faion_search",
     "description": "Search faion methodology corpus by natural-language query. Returns top-N slugs with summaries.",
     "input_schema": {"type": "object", "properties": {"query": {"type": "string"}, "max_results": {"type": "integer", "default": 5}}, "required": ["query"]}},
    {"name": "faion_get_content",
     "description": "Fetch a methodology file by slug. On 403, returns preview + tier hint.",
     "input_schema": {"type": "object", "properties": {"slug": {"type": "string"}, "file": {"type": "string", "default": "AGENTS.md"}}, "required": ["slug"]}}
  ],
  "system_prompt": "You may consult faion methodologies via faion_search and faion_get_content. Call at most 3 tools per turn. On 403, surface the preview and stop.",
  "dispatcher": {"cache": true, "pii_strip": true, "logging": true}
}
